SIMPLIFY_INSTRUCTION = """
Simplify the conditional logic in this function. Permitted transformations:
- Convert nested if/else into guard clauses with early returns
- Apply de Morgan's law to simplify boolean expressions
- Replace if/elif chains with dictionary lookups where the values are constants
- Invert conditions to reduce nesting depth
Forbidden: change the return type, change behavior for any input, add error handling
that was not present, remove branches. Preserve all docstrings and type annotations.
"""

# Example: deeply nested function
source_to_simplify = '''
def classify_transaction(amount: float, account_type: str, is_weekend: bool) -> str:
    if amount > 0:
        if account_type == "checking":
            if is_weekend:
                return "checking_weekend_credit"
            else:
                return "checking_weekday_credit"
        else:
            if account_type == "savings":
                if is_weekend:
                    return "savings_weekend_credit"
                else:
                    return "savings_weekday_credit"
            else:
                return "other_credit"
    else:
        if not account_type == "checking":
            return "non_checking_debit"
        else:
            if amount < -1000:
                return "large_checking_debit"
            else:
                return "small_checking_debit"
'''

result = refactor(source_to_simplify, SIMPLIFY_INSTRUCTION)
print(result.unified_diff)
